"use client";

import { createContext, useContext, useState, ReactNode } from "react";

type Reminder = {
  id: string;
  plantName: string;
};

type ReminderContextType = {
  reminders: Reminder[];
  addReminder: (plantName: string) => void;
  removeReminder: (id: string) => void;
};

const ReminderContext = createContext<ReminderContextType | undefined>(
  undefined
);

export function ReminderProvider({ children }: { children: ReactNode }) {
  const [reminders, setReminders] = useState<Reminder[]>([]);

  const addReminder = (plantName: string) => {
    setReminders((prev) => [
      ...prev,
      { id: Date.now().toString(), plantName },
    ]);
  };

  const removeReminder = (id: string) => {
    setReminders((prev) => prev.filter((r) => r.id !== id));
  };

  return (
    <ReminderContext.Provider
      value={{ reminders, addReminder, removeReminder }}
    >
      {children}
    </ReminderContext.Provider>
  );
}

export function useReminders() {
  const context = useContext(ReminderContext);
  if (!context) {
    throw new Error("useReminders must be used inside ReminderProvider");
  }
  return context;
}
