'use client';

import { useState } from 'react';
import { useReminders } from '../context/ReminderContext';

const plants = [
  { name: 'Money Plant', description: 'Low maintenance indoor plant' },
  { name: 'Neem', description: 'Medicinal plant' },
  { name: 'Tulsi', description: 'Sacred plant' },
];

export default function SearchPage() {
  const [query, setQuery] = useState('');
  const { addReminder } = useReminders();

  const filteredPlants = plants.filter((plant) =>
    plant.name.toLowerCase().includes(query.toLowerCase())
  );

  return (
    <div className="p-8 text-white">
      <h1 className="text-3xl font-bold mb-4">Search Plants 🌱</h1>

      {/* ✅ SEARCH BAR RESTORED */}
      <div className="flex gap-2 mb-6">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search plant..."
          className="px-4 py-2 rounded text-black w-64"
        />
      </div>

      {/* PLANT LIST */}
      <div className="space-y-4">
        {filteredPlants.map((plant) => (
          <div
            key={plant.name}
            className="bg-slate-800 p-4 rounded flex justify-between items-center"
          >
            <div>
              <h2 className="text-lg font-semibold">{plant.name}</h2>
              <p className="text-gray-400">{plant.description}</p>
            </div>

            <button
              onClick={() => addReminder(plant.name)}
              className="bg-green-600 px-4 py-2 rounded hover:bg-green-700"
            >
              ⏰ Add Reminder
            </button>
          </div>
        ))}

        {filteredPlants.length === 0 && (
          <p className="text-red-400">No plants found</p>
        )}
      </div>
    </div>
  );
}
